const body = $json.body ?? $json;
const data = body.data ?? body;
const remoteJid = data.key?.remoteJid ?? data.remoteJid ?? body.remoteJid ?? '';
const telefone = String(remoteJid || data.from || body.from || '').replace(/\D/g, '').replace(/^244/, '');
const texto = data.message?.conversation ?? data.message?.extendedTextMessage?.text ?? body.text ?? body.message ?? '';
return telefone && texto ? [{ json: { telefone, texto } }] : [];

const contexto = $json;
const cliente = contexto.cliente ?? {};
const reserva = contexto.reservaAtiva;
const peca = contexto.pecaReservada ?? reserva?.peca;
const telefone = cliente.telefone ? `244${String(cliente.telefone).replace(/^244/, '')}` : null;
if (!telefone) return [];
const nome = cliente.nome || 'cliente';
let texto;
if (!reserva) texto = `Olá, ${nome}. Não encontrei uma reserva ativa neste número. Vou chamar a equipa para ajudar.`;
else if (reserva.estadoPagamento === 'CONFIRMADO' || reserva.estado === 'PAID') texto = `Olá, ${nome}. O pagamento da peça #${reserva.codigoPeca} está confirmado. A equipa vai seguir com a entrega.`;
else if (reserva.estado === 'WAITLISTED') texto = `Olá, ${nome}. Estás na fila da peça #${reserva.codigoPeca}. Se chegar a tua vez, avisamos por aqui.`;
else {
  const minutos = reserva.tempoRestanteSegundos != null ? Math.ceil(reserva.tempoRestanteSegundos / 60) : null;
  const preco = peca?.precoEmKwanza ? new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA', maximumFractionDigits: 0 }).format(peca.precoEmKwanza) : 'preço indisponível';
  texto = `Olá, ${nome}. A tua reserva da peça #${reserva.codigoPeca} está ativa.\nPreço: ${preco}\n${minutos != null ? `Tempo restante: ${minutos} min\n` : ''}Envia o comprovativo por aqui depois do pagamento.`;
}
return [{ json: { telefone, texto } }];
